#!/usr/bin/env python
"""
Bootstrap: Orientation-Aware Window Coating
  EXTERIOR, INTERIOR, IGU_SURFACE_2/3, DUAL (both sides)
  Glass UV pre-filtering model (sigmoidal 320nm cutoff)
  Adhesion layer for glass-contact, self-clean only on exterior
  Iridescence direction (street vs room), switchable on interior
  36 tests, 670 total, zero regression.
Usage: python bootstrap_window_orientation.py
"""
import base64, os, sys
if os.path.isfile("core/universal_schema.py"): root="."
elif os.path.isfile(os.path.join("..","core","universal_schema.py")): root=".."; os.chdir(root)
else: print("ERROR: Run from MABE root"); sys.exit(1)
FILES = {
    'core/window_orientation.py': '',
    'tests/test_window_orientation.py': '',
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "w", encoding="utf-8") as f: f.write(content)
    print(f"  Wrote {path} ({len(content)} bytes)")
print("Done.")